// modules/files/module.contract.ts
import { defineContract } from 'aether';

export default defineContract({
  name: 'files',
  description: 'Handles file storage and retrieval, ensuring access control based on team membership.',

  dependencies: { modules: ['auth'] },

  exposes: {
    routes: [
      { method: 'GET', path: '/files/download/:fileId', auth: true },
    ],
    functions: ['getFile'],
    types: ['File', 'AccessDeniedError'],
  },

  sideEffects: [
    'reads from: files table',
    'reads from: team_memberships table',
  ],

  invariants: [
    'A file must belong to exactly one team',
    'Only members of a file\'s owning team can access it',
    '404 should be returned on access denied to avoid existence leak',
  ],
});

